    return(
        <form>

            <input type="file" placehoder={'Title'}/>
            <input type="summary" placehoder={'Summary'}/>
            <input type="file"/>
            <textarea name="" id="" cols="30" rows="10"></textarea>
            <ReactQuill/>

        </form>
    )
}
